def _make_question(slug, topic, difficulty, mode, question, correct, wrongs, explanation):
    options = list(wrongs)
    answer_index = sum(ord(c) for c in slug) % (len(options) + 1)
    options.insert(answer_index, correct)
    
    custom_exps = SPECS_EXPLANATIONS.get(slug, {})
    wrong_explanations = []
    for i, option in enumerate(options):
        if i == answer_index:
            wrong_explanations.append("This is the best answer.")
        else:
            wrong_explanations.append(
                custom_exps.get(option) or "This option misses the key concept or overstates what the technique does."
            )
            
    return {
        "slug": slug,
        "topic": topic,
        "difficulty": difficulty,
        "mode": mode,
        "question": question,
        "options": options,
        "answer_index": answer_index,
        "explanation": explanation,
        "wrong_explanations": wrong_explanations,
    }


