def _make_practical_drill(slug, topic, difficulty, mode, concept, correct, explanation):
    # Retrieve all unique guidelines for this mode
    mode_guidelines = MODE_GUIDELINES.get(mode, [])
    
    # Try to find the index of the correct guideline in the list
    try:
        idx = mode_guidelines.index(correct)
    except ValueError:
        idx = 0
        
    # Select 3 distractors deterministically
    distractors = []
    offset = 1
    # Fallback list of generic anti-patterns in case mode_guidelines is too small
    generic_wrongs = [
        "Let the model edit broadly before reading the relevant code",
        "Treat a clean-looking patch as correct without running checks",
        "Hide uncertainty instead of recording assumptions and validation gaps"
    ]
    while len(distractors) < 3:
        if len(mode_guidelines) > 3:
            candidate = mode_guidelines[(idx + offset) % len(mode_guidelines)]
            if candidate != correct and candidate not in distractors:
                distractors.append(candidate)
        else:
            candidate = generic_wrongs[offset % len(generic_wrongs)]
            if candidate != correct and candidate not in distractors:
                distractors.append(candidate)
        offset += 1
        
    options = [correct] + distractors
    
    # Deterministically calculate the answer index
    answer_index = sum(ord(c) for c in slug) % len(options)
    options[0], options[answer_index] = options[answer_index], options[0]
    
    wrong_explanations = []
    for i, option in enumerate(options):
        if i == answer_index:
            wrong_explanations.append(f"Correct: {explanation}")
        else:
            info = DRILL_LOOKUP.get(option)
            if info:
                wrong_explanations.append(
                    f"Not best for {concept}: This is the guideline for {info['concept']} "
                    f"({info['explanation']})."
                )
            else:
                wrong_explanations.append(f"Not best for {concept}.")
                
    return {
        "slug": slug,
        "topic": topic,
        "difficulty": difficulty,
        "mode": mode,
        "question": f"For {concept}, what is the best practical guideline?",
        "options": options,
        "answer_index": answer_index,
        "explanation": explanation,
        "wrong_explanations": wrong_explanations,
    }


