# Build lookup maps for dynamic distractors
DRILL_LOOKUP = {}
MODE_GUIDELINES = {}

for (mode, difficulty), drills in _PRACTICAL_DRILLS.items():
    if mode not in MODE_GUIDELINES:
        MODE_GUIDELINES[mode] = []
    for topic, concept, correct, explanation in drills:
        DRILL_LOOKUP[correct] = {
            "topic": topic,
            "concept": concept,
            "explanation": explanation
        }
        if correct not in MODE_GUIDELINES[mode]:
            MODE_GUIDELINES[mode].append(correct)

for (mode, difficulty), drills in _PRACTICAL_DRILLS.items():
    QUESTION_BANK.extend(
        _make_practical_drill(
            f"practical-{mode}-{difficulty}-{i}-{topic.lower().replace(' ', '-')}-{concept.lower().replace(' ', '-')}",
            topic,
            difficulty,
            mode,
            concept,
            correct,
            explanation,
        )
        for i, (topic, concept, correct, explanation) in enumerate(drills, start=1)
    )
